<script lang="ts">
  import { onMount } from "svelte";
  import { TickerImpl } from "./ticker.js";
  import { Walker } from "./walker.js";
  import { KMLMap } from "./kmlmap.js";
  import { Chart } from "./chart.js";

  type Mode = "bike" | "walk";

  let index: number = 0;
  let tracker: number = -1;
  let time: string = "00:00:00";
  let speed: number = 0;
  let ff: number = 10;
  let distance: number = 0;
  let paused: boolean = false;
  let ticker: ReturnType<typeof TickerImpl.create>;
  let kmlMap: ReturnType<typeof KMLMap.create>;
  let chart: ReturnType<typeof Chart.create>;
  let live: boolean = false;
  let mode: Mode = "bike";
  let walkers: ReturnType<typeof Walker.create>[] = [];
  let walkerModes: Mode[] = [];
  let colors: string[] = ["#008bab", "#a9608a", "#588045", "#a66323"];
  let lag: number = 0;
  let anyLag: boolean = false;
  let lagCounts: number[] = [0, 0, 0, 0];

  function secToDayTime(seconds: number): string {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    return [h, m, s].map((n) => String(n).padStart(2, "0")).join(":");
  }

  async function handleTrack(i: number): Promise<void> {
    if (i == tracker) {
      walkers[tracker].watch(false);
      walkers[tracker].info(null);
      tracker = -1;
      return;
    }
    if (tracker != -1) {
      walkers[tracker].watch(false);
      walkers[tracker].info(null);
    }
    tracker = i;
    const walker = walkers[tracker];
    walker.watch(true);
    walker.info((d: number, t: number, s: number) => {
      distance = d;
      time = secToDayTime(t);
      speed = s;
    });
    await chart.load(walker.trackData());
  }

  function handleUpload(): void {
    if (index > 3) {
      alert("ERROR: Upload limit.");
      return;
    }
    if (ticker.live()) {
      return;
    }
    const elm = document.getElementById("upload") as HTMLInputElement;
    elm.click();
  }

  function handleKml(event: Event): void {
    const input = event.target as HTMLInputElement;
    const file = input.files![0];
    const reader = new FileReader();
    reader.onload = async () => {
      const imageName = mode === "walk" ? "walker-" + index : "bike-helmet-" + index;
      const imageExt = ".png";
      const walker = Walker.create(
        "id" + index,
        kmlMap,
        imageName,
        imageExt,
        colors[index],
        reader.result as string
      );
      walkerModes[index] = mode;
      ticker.add(walker.callback);
      const isGpx = file.name.toLowerCase().endsWith(".gpx");
      const trackData = isGpx
        ? await kmlMap.loadGpx(walker, mode)
        : await kmlMap.loadKml(walker, mode);
      await chart.load(trackData);
      chart.point(0);
      walker.speed(ff);
      walker.point(chart.point);
      const walkerIndex = index;
      walker.lag((n: number) => {
        lagCounts[walkerIndex] = n;
        anyLag = lagCounts.some((c) => c > 0);
        if (walkerIndex === tracker) lag = n;
      });
      walkers.push(walker);
      walkers = walkers;
      await handleTrack(index);
      chart.point(0);
      index++;
    };
    reader.readAsText(file);
  }

  async function handleStart(): Promise<void> {
    if (index == 0 || live) {
      return;
    }
    live = true;
    distance = 0;
    lag = 0;
    anyLag = false;
    lagCounts = [0, 0, 0, 0];
    await ticker.start();
  }

  onMount(() => {
    jQuery(".dropdown").dropdown({
      onChange: function (value: string) {
        ff = Number(value);
        for (const walker of walkers) {
          walker.speed(ff);
        }
      },
    });
    ticker = TickerImpl.create();
    ticker.finished(() => {
      live = false;
    });
    kmlMap = KMLMap.create("map");
    chart = Chart.create();
    chart.click((d: { index: number }) => {
      if (!live) {
        chart.point(d.index);
        if (tracker != -1) {
          walkers[tracker].pos(d.index);
        }
      }
    });
    chart.show();

    const map = kmlMap.getMap();
    map.on("movestart", () => {
      ticker.pause();
    });

    map.on("moveend", () => {
      if (!paused) {
        ticker.resume();
      }
    });

    document.addEventListener("visibilitychange", () => {
      if (document.visibilityState === "visible") {
        ticker.resume();
      }
      if (document.visibilityState === "hidden") {
        ticker.pause();
      }
    });
  });
</script>

<div id="control">
  <input id="upload" type="file" accept=".kml,.gpx" on:change={handleKml} style="display: none" />
  {#each walkers as walker, i}
    <!-- svelte-ignore a11y-missing-attribute -->
    <!-- svelte-ignore a11y-click-events-have-key-events -->
    <img
      src="{walkerModes[i] === 'walk' ? 'walker' : 'bike-helmet'}-{i}.png"
      class:tracker={i == tracker}
      title="参加者 {i + 1} を選択"
      on:click={() => {
        handleTrack(i);
      }}
    />
  {/each}
  <button
    class="circular ui icon button"
    class:blue={index > 0}
    title="再生"
    on:click={async () => {
      await handleStart();
    }}
  >
    <i class="icon play" class:white={!live} class:yellow={live}></i>
  </button>
  <button
    class="circular ui icon button"
    class:blue={index > 0}
    title="一時停止 / 再開"
    on:click={async () => {
      if (!live) return;
      if (!paused) {
        ticker.pause();
      } else {
        ticker.resume();
      }
      paused = !paused;
    }}
  >
    <i class="icon pause" class:white={!paused} class:yellow={paused}></i>
  </button>
  <button
    class="circular ui icon button"
    class:red={index > 0}
    title="停止"
    on:click={async () => {
      paused = false;
      lag = 0;
      anyLag = false;
      lagCounts = [0, 0, 0, 0];
      ticker.stop();
    }}
  >
    <i class="white icon stop"></i>
  </button>

  <button
    class="circular ui icon button"
    class:teal={mode === "bike"}
    class:orange={mode === "walk"}
    on:click={() => {
      mode = mode === "bike" ? "walk" : "bike";
    }}
    title={mode === "bike" ? "自転車モード" : "ウォーキングモード"}
  >
    <i class="icon" class:bicycle={mode === "bike"} class:walking={mode === "walk"}></i>
  </button>
  <button
    class="circular pink ui icon button"
    title="ファイルをアップロード (.kml / .gpx)"
    on:click={handleUpload}
  >
    <i class="icon cloud upload"></i>
  </button>
  <a href="manual.html" target="_blank" class="circular ui icon button" title="操作マニュアル">
    <i class="icon question"></i>
  </a>
  <div id="xspeed" class="ui selection dropdown" class:disabled={live} class:lag={anyLag}>
    <i class="fast forward icon"></i>
    <span class="text">Rate</span>
    <div class="menu">
      <div class="item">10</div>
      <div class="item">50</div>
      <div class="item">100</div>
      <div class="item">500</div>
      <div class="item">1000</div>
    </div>
  </div>
</div>
<div id="map"></div>
<div id="chart"></div>
<div
  id="data"
  class:color={tracker == -1}
  class:color0={tracker == 0}
  class:color1={tracker == 1}
  class:color2={tracker == 2}
  class:color3={tracker == 3}
>
  <div id="time">{time}</div>
  <div id="distance">{distance}km</div>
  <div id="speed">{speed}km/h</div>
  <div id="lag">{lag > 0 ? `⚠${lag}` : ""}</div>
</div>

