import sha256 from "crypto-js/sha256";
import Base64 from "crypto-js/enc-base64";
export let Ticker = {
  STARTED: 0,
  RUNNING: 1,
  PAUSED: 2,
  FINISHED: 3,
  RUN: 4,
  PAUSE: 5,
  STOP: 6,
  RESET: 7,
};

export let TickerImpl = Object.assign(Ticker, {
  STARTED: 0,
  RUNNING: 1,
  PAUSED: 2,
  FINISHED: 3,
  RUN: 4,
  PAUSE: 5,
  STOP: 6,
  RESET: 7,
  create: () => {
    let cancel = true;
    let pause = false;
    let callback = [];
    let skip = [];
    let dead = 0;
    let tref = null;
    let start_ts = -1;
    let ts = 0;
    let pause_ts = 0;
    let cb_finished;
    let state = Ticker.STOP;
    function loop(t) {
      if (start_ts == -1) {
        start_ts = t;
      }
      ts = t - start_ts + pause_ts;
      if (cancel) return;
      for (let i = 0; i < callback.length; i++) {
        if (skip[i]) continue;
        let state = callback[i](Ticker.RUNNING, ts);
        if (state == Ticker.STOP) {
          skip[i] = true;
          dead += 1;
        } else if (state == Ticker.PAUSE) {
          pause_ts = ts;
          start_ts = -1;
        }
      }
      if (dead >= callback.length) {
        terminate();
        state = Ticker.STOP;
        cb_finished && cb_finished();
      } else if (!cancel) {
        tref = requestAnimationFrame(loop.bind(this));
      }
    }
    function terminate() {
      if (tref) {
        cancelAnimationFrame(tref);
        cancel = true;
        tref = null;
      }
    }
    return {
      finished: (cb) => {
        cb_finished = cb;
      },
      live: () => {
        return state == Ticker.STARTED;
      },
      start: () => {
        /*
        if (
          "BzW36AqiPgX2K/AhfNlvmK2MnDrfHEzt85iVtjcxGoE=" !=
          Base64.stringify(sha256(new URL(location.href).hostname))
        )
          return;
		  */
        if (!cancel) return;
        if (!pause) {
          for (let i = 0; i < callback.length; i++) {
            skip[i] = false;
            callback[i](Ticker.STARTED);
          }
          state = Ticker.STARTED;
          cancel = false;
          dead = 0;
          start_ts = -1;
          pause_ts = 0;
          tref = requestAnimationFrame(loop);
        }
      },
      resume: () => {
        if (pause) {
          cancel = false;
          pause = false;
          tref = requestAnimationFrame(loop);
        }
      },
      pause: () => {
        if (!cancel) {
          pause = true;
          pause_ts = ts;
          start_ts = -1;
          terminate();
          for (let cb of callback) {
            cb(Ticker.PAUSED, ts);
          }
        }
      },
      stop: () => {
        pause = false;
        state = Ticker.STOP;
        for (let i = 0; i < callback.length; i++) {
          callback[i](Ticker.RESET, 0);
        }
        terminate();
        cb_finished && cb_finished();
      },
      add: (cb) => {
        callback.push(cb);
      },
    };
  },
});
