import sha256 from "crypto-js/sha256";
import Base64 from "crypto-js/enc-base64";
export let KMLMap = {
  create: (mapId) => {
    let walkers = [];
    let map_extent = [
      Number.MAX_SAFE_INTEGER,
      Number.MAX_SAFE_INTEGER,
      -Number.MAX_SAFE_INTEGER,
      -Number.MAX_SAFE_INTEGER,
    ];

    /*
    let map = new ol.Map({
      target: mapId,
      layers: [new ol.layer.Tile({ source: new ol.source.OSM() })],
      view: new ol.View({ center: [0, 0], padding: [50, 50, 50, 50], zoom: 10, }),
    });
	*/

    const openfreemap = new ol.layer.Group();
    let map = new ol.Map({
      target: mapId,
      layers: [openfreemap],
      view: new ol.View({ center: [0, 0], padding: [50, 50, 50, 50], zoom: 10 }),
    });
    olms.apply(openfreemap, "https://tiles.openfreemap.org/styles/liberty");

    function getMap() {
      return map;
    }

    function get_extent(extent) {
      if (extent[0] < map_extent[0]) {
        map_extent[0] = extent[0];
      }
      if (extent[1] < map_extent[1]) {
        map_extent[1] = extent[1];
      }
      if (extent[2] > map_extent[2]) {
        map_extent[2] = extent[2];
      }
      if (extent[3] > map_extent[3]) {
        map_extent[3] = extent[3];
      }
      return map_extent;
    }

    function createSource(data, format) {
      let olFormat =
        format === "gpx"
          ? new ol.format.GPX()
          : new ol.format.KML({ extractStyles: true, writeStyles: true });
      let source = new ol.source.Vector({
        format: olFormat,
        loader: function (extent, resolution, projection, success, failure) {
          let features = source.getFormat().readFeatures(data, {
            dataProjection: "EPSG:4326",
            featureProjection: "EPSG:3857",
          });
          source.addFeatures(features);
          success(features);
        },
      });
      return source;
    }

    function createOverlay(coord, elm) {
      let overlay = new ol.Overlay({
        element: elm,
        position: coord,
        positioning: "center-center",
        className: "ol-overlay-container ol-selectable",
      });
      map.addOverlay(overlay);
      return overlay;
    }

    const MODE_PARAMS = {
      bike: { ACCEL_LIMIT: 7.0, MIN_MOVING_SPEED_KMH: 1.0, MIN_SPIKE_DIST: 20 },
      walk: { ACCEL_LIMIT: 3.0, MIN_MOVING_SPEED_KMH: 1.0, MIN_SPIKE_DIST: 5 },
    };

    function removeNoise(coords, params) {
      const ACCEL_LIMIT = params.ACCEL_LIMIT;
      const MIN_MOVING_SPEED = params.MIN_MOVING_SPEED_KMH / 3.6; // m/s に変換
      if (coords.length < 2) return coords;

      let result = [];
      let prevSpeed = null;
      let stationaryCount = 0;
      let noiseCount = 0;

      for (let i = 0; i < coords.length; i++) {
        let curr = coords[i];

        if (result.length === 0) {
          result.push(curr);
          continue;
        }

        // 停止判定: 直前の元ポイントとの瞬間速度で判断する
        // （result末尾を使うとポイント削除時にdtが積み上がりカスケード削除が起きるため）
        let origPrev = coords[i - 1];
        if (curr[3] && origPrev[3]) {
          let dtOrig = (curr[3] - origPrev[3]) / 1000;
          if (dtOrig > 0) {
            let distOrig = ol.sphere.getDistance(
              ol.proj.toLonLat(origPrev),
              ol.proj.toLonLat(curr)
            );
            let instantSpeed = distOrig / dtOrig;
            if (instantSpeed < MIN_MOVING_SPEED) {
              if (prevSpeed !== 0) {
                result.push(curr); // 停止開始点のみ保持
              }
              prevSpeed = 0;
              stationaryCount++;
              continue;
            }
          }
        }

        // ノイズ判定: 最後に保持したポイントとの加速度で判断する
        let prev = result[result.length - 1];

        if (!curr[3] || !prev[3]) {
          result.push(curr);
          continue;
        }

        let dt = (curr[3] - prev[3]) / 1000; // ms → s
        if (dt <= 0) continue;

        let dist = ol.sphere.getDistance(ol.proj.toLonLat(prev), ol.proj.toLonLat(curr));
        let currSpeed = dist / dt;

        if (prevSpeed === null) {
          // 直前の速度なし（先頭区間）: 静止状態からの加速度で検証
          let accel = currSpeed / dt;
          if (accel > ACCEL_LIMIT) {
            // どちらが正しい位置か不明なので先頭ポイントを削除し、currを新たな先頭とする
            result.pop();
            result.push(curr);
          } else {
            prevSpeed = currSpeed;
            result.push(curr);
          }
        } else {
          let accel = Math.abs(currSpeed - prevSpeed) / dt;
          if (accel <= ACCEL_LIMIT) {
            prevSpeed = currSpeed;
            result.push(curr);
          } else {
            // ノイズ: ジャンプ方向は信頼できないため削除する
            // （連続するGPSジャンプで誤方向に積み上がるドリフトを防ぐ）
            noiseCount++;
          }
        }
      }

      console.log(
        `[removeNoise] stationary: ${stationaryCount}, noise: ${noiseCount} removed (${coords.length} → ${result.length})`
      );
      return result;
    }

    function removeSpikes(coords, params) {
      const SPIKE_RATIO = 2.0; // prev→curr + curr→next が prev→next の何倍以上でスパイクとみなすか
      const MIN_SPIKE_DIST = params.MIN_SPIKE_DIST; // m: これ未満のジャンプはスパイク判定しない（Uターン誤判定防止）
      if (coords.length < 3) return coords;

      let result = [coords[0]];
      let spikeCount = 0;

      for (let i = 1; i < coords.length - 1; i++) {
        let prev = result[result.length - 1];
        let curr = coords[i];
        let next = coords[i + 1];

        let dPrevCurr = ol.sphere.getDistance(ol.proj.toLonLat(prev), ol.proj.toLonLat(curr));
        let dCurrNext = ol.sphere.getDistance(ol.proj.toLonLat(curr), ol.proj.toLonLat(next));
        let dPrevNext = ol.sphere.getDistance(ol.proj.toLonLat(prev), ol.proj.toLonLat(next));

        if (
          dPrevCurr >= MIN_SPIKE_DIST &&
          dPrevNext > 0 &&
          dPrevCurr + dCurrNext > SPIKE_RATIO * dPrevNext
        ) {
          spikeCount++;
          continue;
        }
        result.push(curr);
      }
      result.push(coords[coords.length - 1]);

      console.log(`[removeSpikes] ${spikeCount} removed (${coords.length} → ${result.length})`);
      return result;
    }

    function perpDist(point, a, b) {
      let dx = b[0] - a[0];
      let dy = b[1] - a[1];
      if (dx === 0 && dy === 0) {
        let px = point[0] - a[0];
        let py = point[1] - a[1];
        return Math.sqrt(px * px + py * py);
      }
      let len = Math.sqrt(dx * dx + dy * dy);
      return Math.abs((point[0] - a[0]) * dy - (point[1] - a[1]) * dx) / len;
    }

    function rdp(points, epsilon, _topLevel = true) {
      if (points.length < 3) return points;
      let start = points[0];
      let end = points[points.length - 1];
      let maxDist = 0;
      let maxIdx = 0;
      for (let i = 1; i < points.length - 1; i++) {
        let d = perpDist(points[i], start, end);
        if (d > maxDist) {
          maxDist = d;
          maxIdx = i;
        }
      }
      if (_topLevel) {
        console.log(
          `[rdp] coord[0]=${JSON.stringify(start)}, maxDist=${maxDist}, epsilon=${epsilon}`
        );
      }
      if (maxDist > epsilon) {
        let left = rdp(points.slice(0, maxIdx + 1), epsilon, false);
        let right = rdp(points.slice(maxIdx), epsilon, false);
        return left.slice(0, -1).concat(right);
      }
      return [start, end];
    }

    function displayTrack(walker, source, mode) {
      let coordArray = [];
      let features = source.getFeatures();
      let extent = get_extent(source.getExtent());
      let emptyStyle = new ol.style.Style({});
      map.getView().fit(extent, map.getSize());
      for (let feature of features) {
        let geometry = feature.getGeometry();
        if (!geometry) continue;
        let type = geometry.getType();
        if (type == "LineString") {
          feature.setStyle(
            new ol.style.Style({
              stroke: new ol.style.Stroke({
                color: walker.color(),
                width: 3,
              }),
            })
          );
          coordArray = coordArray.concat(geometry.getCoordinates());
        } else if (type == "MultiLineString") {
          feature.setStyle(
            new ol.style.Style({
              stroke: new ol.style.Stroke({
                color: walker.color(),
                width: 3,
              }),
            })
          );
          for (let line of geometry.getCoordinates()) {
            coordArray = coordArray.concat(line);
          }
        } else if (type == "Point") {
          feature.setStyle(emptyStyle);
        }
      }
      // GPXはタイムスタンプが秒単位のため、msに統一する
      if (coordArray.length > 0 && coordArray[0][3] && coordArray[0][3] < 1e11) {
        coordArray = coordArray.map((c) => {
          if (c[3] == null) return c;
          let nc = c.slice();
          nc[3] = nc[3] * 1000;
          return nc;
        });
      }
      const params = MODE_PARAMS[mode] || MODE_PARAMS.bike;
      let beforeNoise = coordArray.length;
      coordArray = removeNoise(coordArray, params);
      let beforeSpike = coordArray.length;
      coordArray = removeSpikes(coordArray, params);
      let beforeRdp = coordArray.length;
      // epsilonを実メートル→EPSG:3857単位に変換（メルカトルスケール係数で補正）
      const RDP_EPSILON_M = 1;
      const latRad = (ol.proj.toLonLat(coordArray[0])[1] * Math.PI) / 180;
      const epsilonEpsg = RDP_EPSILON_M / Math.cos(latRad);
      coordArray = rdp(coordArray, epsilonEpsg);
      console.log(
        `[filter] noise: ${beforeNoise - beforeSpike} removed (${beforeNoise} → ${beforeSpike}), spike: ${beforeSpike - beforeRdp} removed (${beforeSpike} → ${beforeRdp}), rdp: ${beforeRdp - coordArray.length} removed (${beforeRdp} → ${coordArray.length})`
      );

      source.clear();
      let filteredFeature = new ol.Feature({
        geometry: new ol.geom.LineString(coordArray),
      });
      filteredFeature.setStyle(
        new ol.style.Style({
          stroke: new ol.style.Stroke({ color: walker.color(), width: 3 }),
        })
      );
      source.addFeature(filteredFeature);

      return walker.coordinates(coordArray);
    }

    async function loadTrack(walker, format, mode) {
      let source = createSource(walker.track(), format);
      map.addLayer(
        new ol.layer.Vector({
          source: source,
          style: new ol.style.Style({
            stroke: new ol.style.Stroke({ color: "#0000ff", width: 3 }),
          }),
        })
      );

      return await new Promise((resolve) => {
        source.once("change", function (e) {
          if (source.getState() != "ready") {
            resolve();
            return;
          }
          let trackData = displayTrack(walker, source, mode);
          resolve(trackData);
        });
      });
    }

    return {
      createOverlay: createOverlay,
      getMap: getMap,
      loadKml: async (walker, mode) => {
        /*
        if (
          "BzW36AqiPgX2K/AhfNlvmK2MnDrfHEzt85iVtjcxGoE=" !=
          Base64.stringify(sha256(new URL(location.href).hostname))
        )
          return;
		  */
        return await loadTrack(walker, "kml", mode);
      },
      loadGpx: async (walker, mode) => {
        return await loadTrack(walker, "gpx", mode);
      },
      loadKmls: async (list) => {
        walkers = list;
        for (let walker of walkers) {
          await loadTrack(walker, "kml");
        }
      },
    };
  },
};
