import { Ticker } from "./ticker.js";
export let Walker = {
  create: (id, kmlMap, image, imageExt, color, kml) => {
    let speed = 100;
    let index = 0;
    let coordArray = [];
    let overlay;
    let elm;
    let trackData = {
      distance: [],
      elevation: [],
      time: [],
      ts: [],
    };
    let map = kmlMap.getMap();
    let isCenter = false;
    let watch = false;
    let cb_point;
    let cb_info;
    let distance = 0;
    let kmh = 0;
    let ts = 0;
    let cb_lag;
    return {
      trackData: function () {
        return trackData;
      },
      color: function () {
        return color;
      },
      speed: function (val) {
        speed = val;
      },
      coordinates: function (arr) {
        coordArray = arr;
        elm = document.createElement("img");
        elm.setAttribute("src", image + imageExt);
        overlay = kmlMap.createOverlay(coordArray[0], elm);
        trackData.distance.push(0);
        if (coordArray[0][2]) {
          trackData.elevation.push(coordArray[0][2]);
        } else {
          trackData.elevation.push(0);
        }
        if (coordArray[0][3]) {
          trackData.time.push(coordArray[0][3]);
        } else {
          trackData.time.push(0);
        }
        trackData.ts.push(0);
        let total = 0;
        let elapsed = 0;
        for (let i = 1; i < coordArray.length; i++) {
          let to = coordArray[i];
          let from = coordArray[i - 1];
          total += ol.sphere.getDistance(ol.proj.toLonLat(from), ol.proj.toLonLat(to)) / 1000;
          trackData.distance.push(total);
          if (to[2]) {
            trackData.elevation.push(to[2]);
          } else {
            trackData.elevation.push(0);
          }
          if (to[3]) {
            elapsed += to[3] - from[3];
            trackData.time.push(to[3]);
            trackData.ts.push(elapsed);
          } else {
            trackData.time.push(0);
            trackData.ts.push(0);
          }
        }
        return trackData;
      },
      track: function () {
        return kml;
      },
      watch: function (b) {
        watch = b;
      },
      point: function (cb) {
        cb_point = cb;
      },
      pos: function (i) {
        overlay.setPosition(coordArray[i]);
        let view = map.getView();
        view.setCenter(coordArray[i]);
      },
      lag: function (cb) {
        cb_lag = cb;
      },
      info: function (cb) {
        cb_info = cb;
        cb_info && cb_info(distance, Math.round((ts / 1000) * speed), kmh);
      },
      callback: function (state, t) {
        ts = t;
        if (state == Ticker.STARTED) {
          index = 0;
          distance = 0;
          kmh = 0;
          elm.setAttribute("src", image + imageExt);
          return Ticker.RUNNING;
        } else if (state == Ticker.PAUSED) {
          elm.parentNode.style.transition = "";
          return Ticker.RUNNING;
        } else if (state == Ticker.RESET) {
          elm.parentNode.style.transition = "";
          overlay.setPosition(coordArray[0]);
          elm.setAttribute("src", image + imageExt);
          cb_point && cb_point(0);
          cb_lag && cb_lag(0);
          cb_info && cb_info(0, 0, 0);
          return Ticker.STOP;
        }

        if (index >= trackData.ts.length - 1) {
          elm.parentNode.style.transition = "";
          cb_info && cb_info(distance, Math.round((ts / 1000) * speed), 0);
          elm.setAttribute("src", image + "-goal" + imageExt);
          return Ticker.STOP;
        }

        let ts_before = Math.round(trackData.ts[index] / speed);
        if (t >= ts_before) {
          if (isCenter) {
            isCenter = false;
            elm.parentNode.style.display = "";
            return Ticker.RUNNING;
          }
          let startIndex = index;
          index++;
          while (index < trackData.ts.length - 1) {
            if (t < Math.round(trackData.ts[index] / speed)) break;
            index++;
          }
          let skipped = index - startIndex - 1;
          cb_lag && cb_lag(skipped);
          let ts_prev = Math.round(trackData.ts[index - 1] / speed);
          let ts_current = Math.round(trackData.ts[index] / speed);
          let view = map.getView();
          let extent = view.calculateExtent();
          if (watch) {
            cb_point && cb_point(index);
            if (
              coordArray[index][0] >= extent[2] ||
              coordArray[index][0] <= extent[0] ||
              coordArray[index][1] >= extent[3] ||
              coordArray[index][1] <= extent[1]
            ) {
              index--;
              elm.parentNode.style.transition = "";
              elm.parentNode.style.display = "none";
              view.setCenter(coordArray[index]);
              isCenter = true;
              return Ticker.PAUSE;
            }
          }
          let delay = (ts_current - ts_prev) / 1000;
          let d = trackData.distance[index] - trackData.distance[index - 1];
          if (delay) {
            elm.parentNode.style.transition = `all ${delay}s linear`;
            overlay.setPosition(coordArray[index]);
            kmh = Math.round(((3600 * d) / (delay * speed)) * 100) / 100;
          }
          distance = Math.round(trackData.distance[index] * 100) / 100;
          cb_info && cb_info(distance, Math.round((ts / 1000) * speed), kmh);
        } else {
          cb_lag && cb_lag(0);
          cb_info && cb_info(distance, Math.round((ts / 1000) * speed), kmh);
        }
        return Ticker.RUNNING;
      },
    };
  },
};
