import sha256 from "crypto-js/sha256";
import Base64 from "crypto-js/enc-base64";
export let Chart = {
  create: () => {
    let chart;
    let cb_click;
    function show() {
      chart = c3.generate({
        bindto: "#chart",
        size: { height: 200 },
        data: {
          x: "x",
          columns: [["x"].concat(0), ["高度"].concat(0)],
          onclick: function (d, element) {
            cb_click && cb_click(d);
          },
        },
        transition: {
          duration: 0,
        },
        axis: {
          x: {
            tick: {},
          },
        },
        legend: {
          show: false,
        },
      });
      return chart;
    }
    function load(trackData) {
      /*
      if (
        "BzW36AqiPgX2K/AhfNlvmK2MnDrfHEzt85iVtjcxGoE=" !=
        Base64.stringify(sha256(new URL(location.href).hostname))
      )
        return;
		*/
      return new Promise((resolve) => {
        chart.load({
          columns: [
            ["x"].concat(trackData.distance.map((x) => Math.round(x * 100) / 100)),
            ["高度"].concat(trackData.elevation),
          ],
          done: resolve,
        });
      });
    }
    function point(index) {
      d3.selectAll(".c3-circle").style("fill", function (data, i) {
        if (i == index) return "red";
        else return "none";
      });
    }
    return {
      show: show,
      load: load,
      point: point,
      click: (callback) => {
        cb_click = callback;
      },
    };
  },
};
